<script lang="ts">import { invoke } from "@tauri-apps/api/core";import { mockMods } from "$lib/mock/data";let { workspace }: any = $props();let searchQuery = $state("");let showAddModal = $state(false);let mods = $state<any[]>([]);$effect(() => {mods = mockMods.filter((m: any) => workspace.config?.mods?.includes(m.id) || false);});function removeMod(modId: string) {invoke("save_pack_config", {id: workspace.id,config: { ...workspace.config, mods: workspace.config.mods.filter((id: string) => id !== modId) }}).catch(console.error);}function addMod(modId: string) {invoke("save_pack_config", {id: workspace.id,config: { ...workspace.config, mods: [...(workspace.config.mods || []), modId] }}).catch(console.error);}let available = $derived(mockMods.filter((m: any) => !(workspace.config?.mods || []).includes(m.id)).filter((m: any) => !searchQuery || m.name.toLowerCase().includes(searchQuery.toLowerCase())));</script>n<div class="flex flex-col gap-4"><div class="flex items-center justify-between"><h3 class="text-lg font-semibold">模组 ({mods.length})</h3><button class="btn btn-primary btn-sm" onclick={() => showAddModal = true}>添加</button></div>{#if mods.length === 0}<div class="py-12 text-center text-base-content/50"><p>暂无模组</p></div>{:else}<table class="table table-zebra"><thead><tr><th>名称</th><th>版本</th><th><span class="max-sm:hidden">MC</span></th><th class="w-20"></th></tr></thead><tbody>{#each mods as mod}<tr><td class="font-medium">{mod.name}</td><td>{mod.version}</td><td><span class="badge badge-outline badge-sm">{mod.mc_version}</span></td><td><button class="btn btn-ghost btn-xs text-error" onclick={() => removeMod(mod.id)}>移除</button></td></tr>{/each}</tbody></table>{/if}</div>{#if showAddModal}<div class="modal modal-open"><div class="modal-box"><h3 class="font-bold text-lg mb-4">添加模组</h3><input type="text" class="input input-bordered w-full mb-4" placeholder="搜索..." bind:value={searchQuery} /><div class="max-h-80 overflow-y-auto">{#if available.length === 0}<p class="text-center py-8 text-base-content/50">无匹配</p>{:else}<table class="table"><thead><tr><th>名称</th><th>版本</th><th></th></tr></thead><tbody>{#each available as mod}<tr><td>{mod.name}</td><td>{mod.version}</td><td><button class="btn btn-primary btn-xs" onclick={() => addMod(mod.id)}>添加</button></td></tr>{/each}</tbody></table>{/if}</div><div class="modal-action"><button class="btn" onclick={() => { showAddModal = false; searchQuery = ''; }}>关闭</button></div></div></div>{/if}